SELECT AVG(price) AS average_price
FROM trading_data
WHERE symbol_id = 1;

SELECT COUNT(session_id) AS total_sessions
FROM trading_sessions
WHERE user_id = 1;

SELECT MAX(high) AS max_high_price
FROM trading_data
WHERE datetime LIKE '2022-05-09%';

SELECT AVG(market_cap) AS average_market_cap, sector
FROM securities
GROUP BY sector;

SELECT MAX(profit_loss) AS max_profit_loss
FROM backtesting_results
WHERE strategy_id = 1;
